const data = {
  name: 'Alice',
  age: 28,
  greet: () => 'Hello',    // ← function: DROPPED
  alias: undefined,         // ← undefined: DROPPED
  score: NaN,               // ← NaN → null
  max: Infinity,            // ← Infinity → null
  birthday: new Date('2000-01-01'), // ← Date → ISO string
  symbol: Symbol('id'),     // ← Symbol: DROPPED
};

console.log(JSON.stringify(data));
// '{"name":"Alice","age":28,"score":null,"max":null,"birthday":"2000-01-01T00:00:00.000Z"}'

// JSON.stringify(value, replacer, space)
// Third argument: number of spaces for indentation
const obj = { name: 'Alice', scores: [95, 88, 72] };

console.log(JSON.stringify(obj, null, 2));
// {
//   "name": "Alice",
//   "scores": [
//     95,
//     88,
