// Dates are serialized as ISO strings — they don't come back as Date objects!
const event = { name: 'Meeting', date: new Date('2024-03-15') };
const json = JSON.stringify(event);
// '{"name":"Meeting","date":"2024-03-15T00:00:00.000Z"}'

const parsed = JSON.parse(json);
console.log(parsed.date);           // '2024-03-15T00:00:00.000Z' (string, not Date)
console.log(parsed.date instanceof Date); // false!

// Convert back manually when you need a Date object:
const dateObj = new Date(parsed.date);

import { useState, useEffect } from 'react';

function UserList() {
  const [users, setUsers] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('https://api.example.com/users')
      .then(response => {
        if (!response.ok) {
          throw new Error(`HTTP error: ${response.status}`);
        }
        return response.json(); // response.json() calls JSON.parse() internally
      })
      .then(data => setUsers(data))
      .catch(err => setError(err.message));
  }, []);

  if (error) return <p>Error: {error}</p>;

  return (
    <ul>
      {users.map(user => <li key={user.id}>{user.name}</li>)}
    </ul>
  );
}

async function createUser(formData) {
  const response = await fetch('/api/users', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(formData), // serialize to JSON string
  });

  if (!response.ok) throw new Error('Failed to create user');

  const newUser = await response.json(); // parse the JSON response
  return newUser;
}

// localStorage only stores strings — stringify before saving
function saveToStorage(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

function loadFromStorage(key, fallback = null) {
  const stored = localStorage.getItem(key);
  if (stored === null) return fallback;
  try {
    return JSON.parse(stored);
  } catch {
    return fallback; // corrupted data — return fallback
  }
}

// Usage:
saveToStorage('user', { id: 1, name: 'Alice' });
const user = loadFromStorage('user'); // { id: 1, name: 'Alice' }

// JSON round-trip creates a deep clone (simple values only!)
const original = { a: 1, b: { c: 2 } };
const clone = JSON.parse(JSON.stringify(original));

clone.b.c = 99;
console.log(original.b.c); // 2 — original is unchanged

// ⚠️ Limitations: drops functions, undefined, Date (converts to string),
// Map, Set, circular references. Use structuredClone() for a better alternative:
const clone2 = structuredClone(original); // modern browsers and Node 17+
